return $input.all().map(item => {
  const data = item.json;

  const salesNavUrl = data.property_sales_nav_url
    || data.properties?.['Sales Nav URL']?.url
    || '';

  const pageId = data.id || '';
  const name = data.property_campaign
    || data.property_name
    || data.name
    || 'Unnamed';

  return {
    json: {
      notion_page_id: pageId,
      campaign_name: name,
      sales_nav_url: salesNavUrl
    }
  };
}).filter(item => item.json.sales_nav_url);

const notionPageId = $('Loop Over Search URLs').item.json.notion_page_id;
const campaignName = $('Loop Over Search URLs').item.json.campaign_name;

const sanitize = (str, maxLen = 300) =>
  String(str || '')
    .substring(0, maxLen)
    .replace(/[^\x20-\x7E]/g, '')
    .replace(/"/g, "'")
    .replace(/\\/g, '/');

return $input.all().map(item => {
  const profile = item.json;
  return {
    json: {
      notion_page_id: notionPageId,
      campaign_name: campaignName,
      first_name: sanitize(profile.first_name || ''),
      last_name: sanitize(profile.last_name || ''),
      headline: sanitize(profile.headline || '', 200),
      position1_role: sanitize(profile.current_positions?.[0]?.role || ''),
      position1_company: sanitize(profile.current_positions?.[0]?.company || ''),
      location: sanitize(profile.location || ''),
      industry: sanitize(profile.current_positions?.[0]?.industry?.[0] || ''),
      summary: sanitize(profile.summary || '', 300),
      public_profile_url: String(profile.public_profile_url || '')
    }
  };
});;

